 90→  // 判斷搜尋模式
 91→  if (options.sessionId) {
 92→    // 使用 sessionId 搜尋特定 session
 93→    log(
 94→      options.quiet,
 95→      chalk.gray(
 96→        `Searching for ${options.agentType} session "${options.sessionId}"...`
 97→      )
 98→    );
 99→
100→    const finder = agent.finder;
101→    if (!finder.findBySessionId) {
102→      console.error(
103→        chalk.red(
104→          `Session ID lookup not supported for ${options.agentType} agent`
105→        )
106→      );
107→      process.exit(1);
108→    }
109→
110→    const result = await finder.findBySessionId(options.sessionId, {
111→      project: options.project,
