253→/**
254→ * Claude 多檔案監控（主 session + subagents）
255→ * @param initialSubagent - 從 sessionId 參數指定的 subagent（可選）
256→ */
257→async function startClaudeMultiWatch(
258→  sessionFile: SessionFile,
259→  formatter: Formatter,
260→  options: CliOptions,
261→  initialSubagent: SessionFile | null = null
262→): Promise<void> {
263→  const projectDir = dirname(sessionFile.path);
264→  let subagentsDir = getSubagentsDir(sessionFile.path);
265→
266→  // 建立監控檔案列表（主 session）
267→  const files: WatchedFile[] = [{ path: sessionFile.path, label: MAIN_LABEL }];
268→
269→  // 只有在 withSubagents 為 true 時才掃描 subagent
270→  const existingAgentIds = new Set<string>();
271→  if (options.withSubagents) {
272→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
273→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
274→    for (const id of dirAgentIds) {
275→      existingAgentIds.add(id);
276→    }
277→
278→    // 如果有從 sessionId 指定的 subagent，確保它被加入
279→    if (initialSubagent) {
280→      const initialAgentId = basename(initialSubagent.path, '.jsonl').replace(
281→        /^agent-/,
282→        ''
283→      );
284→      existingAgentIds.add(initialAgentId);
285→    }
286→
287→    const existingSubagentFiles = await buildSubagentFiles(
288→      subagentsDir,
289→      existingAgentIds
290→    );
291→    for (const { agentId, path } of existingSubagentFiles) {
292→      files.push({ path, label: makeAgentLabel(agentId) });
293→    }
294→
295→    if (existingAgentIds.size > 0) {
296→      log(
297→        options.quiet,
298→        chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
299→      );
300→    }
301→  }
302→  log(options.quiet, chalk.gray('---'));
303→
304→  // 為每個來源建立獨立的 parser
305→  let parsers = new Map<string, LineParser>();
306→  for (const file of files) {
307→    const parserAgent = new ClaudeAgent({ verbose: options.verbose });
308→    parsers.set(file.label, parserAgent.parser);
309→  }
310→
311→  // 非 follow 模式且有 subagent：收集所有行後按時間排序輸出
312→  if (!options.follow && options.withSubagents && files.length > 1) {
313→    await outputTimeSorted(files, parsers, formatter, options);
314→    process.exit(0);
315→  }
316→
317→  let multiWatcher = new MultiFileWatcher();
318→
319→  // 建立 PaneManager（--pane 模式時自動開啟 tmux pane）
320→  let paneManager: PaneManager | null = null;
321→  if (options.pane) {
322→    const controller = createTerminalController();
323→    if (controller.isAvailable()) {
324→      paneManager = new PaneManager(controller, (agentId, _subagentPath) => {
325→        // 使用當前執行方式重建指令（支援 bun run、npx、全域安裝等）
326→        // 用雙引號包覆路徑，防止空格造成 shell 指令斷裂
327→        const runtime = `"${process.argv[0]}"`;
328→        const script = `"${process.argv[1]}"`;
329→        return `${runtime} ${script} claude --subagent ${agentId} -q --no-pane`;
330→      });
331→    } else {
332→      log(
333→        options.quiet,
334→        chalk.yellow('Warning: tmux not detected, --pane disabled')
335→      );
336→    }
337→  }
338→
339→  // 提取 pane 相關回呼（消除 paneManager! 斷言，用 const 捕獲確認非 null 的參照）
340→  const pm = paneManager; // 閉包捕獲，不受外部重賦值影響
341→  const openPaneForSubagent = pm
342→    ? (agentId: string, subagentPath: string, description?: string) => {
343→        log(options.quiet, chalk.gray(`[pane] Opening pane for ${agentId}...`));
344→        pm.openPane(agentId, subagentPath, description).catch((err) => {
345→          log(
346→            options.quiet,
347→            chalk.yellow(`[pane] Failed to open pane: ${err}`)
348→          );
349→        });
350→      }
351→    : undefined;
352→
353→  const onSubagentDone = pm
354→    ? (agentId: string) => {
355→        const subagentPath = buildSubagentPath(subagentsDir, agentId);
356→
357→        // 先讀取並輸出最後的 assistant 訊息，再關閉 pane
358→        (async () => {
359→          try {
360→            const parts = await readLastAssistantMessage(
361→              subagentPath,
362→              options.verbose
363→            );
364→            const label = makeAgentLabel(agentId);
365→            for (const part of parts) {
366→              part.sourceLabel = label;
367→              console.log(formatter.format(part));
368→            }
369→          } catch {
370→            // 讀取失敗不影響 pane 關閉
371→          } finally {
372→            log(
373→              options.quiet,
