394→        return !pm.hasPaneForAgent(extractAgentIdFromLabel(label));
395→      }
396→    : undefined;
397→
398→  // 建立 SubagentDetector（整合 early detection 和 fallback detection）
399→  let detector = new SubagentDetector(existingAgentIds, {
400→    subagentsDir,
401→    output: new ConsoleOutputHandler(),
402→    watcher: { addFile: (f) => multiWatcher.addFile(f) },
403→    session: new NoOpSessionHandler(),
404→    enabled: options.follow && options.withSubagents,
405→    onNewSubagent: openPaneForSubagent,
406→    onSubagentEnter: openPaneForSubagent,
407→    onSubagentDone,
408→    hasPane: hasPaneCallback,
409→  });
410→  detector.startDirectoryWatch();
411→
412→  // ========== Non-Interactive Super-Follow ==========
413→  let currentSessionPath = sessionFile.path;
414→
415→  const switchToSession = async (
416→    nextSessionFile: SessionFile
417→  ): Promise<void> => {
418→    // 停止現有監控
419→    detector?.stop();
420→    multiWatcher.stop();
421→
422→    // 更新當前 session 路徑
423→    currentSessionPath = nextSessionFile.path;
424→
425→    // 重新初始化監控
426→    const newSessionId = basename(nextSessionFile.path, '.jsonl');
427→    const newSubagentsDir = getSubagentsDir(nextSessionFile.path);
428→
429→    const newFiles: WatchedFile[] = [
430→      { path: nextSessionFile.path, label: MAIN_LABEL },
431→    ];
432→    const newExistingAgentIds = new Set<string>();
433→
434→    // 掃描現有的 subagents
435→    if (options.withSubagents) {
436→      const dirAgentIds = await scanForNewSubagents(newSubagentsDir, new Set());
437→      for (const id of dirAgentIds) {
438→        newExistingAgentIds.add(id);
439→      }
440→
441→      const existingSubagentFiles = await buildSubagentFiles(
442→        newSubagentsDir,
443→        newExistingAgentIds
444→      );
445→      for (const { agentId, path } of existingSubagentFiles) {
446→        newFiles.push({ path, label: makeAgentLabel(agentId) });
447→      }
448→
449→      if (newExistingAgentIds.size > 0) {
450→        log(
451→          options.quiet,
452→          chalk.gray(`Found ${newExistingAgentIds.size} subagent(s)`)
453→        );
454→      }
455→    }
456→
457→    // 輸出切換訊息
458→    log(
459→      options.quiet,
460→      chalk.gray(`--- Switched to session ${newSessionId} ---`)
461→    );
462→    log(options.quiet, chalk.gray('---'));
463→
464→    // 重新建立 parsers
465→    const newParsers = new Map<string, LineParser>();
466→    for (const file of newFiles) {
467→      const parserAgent = new ClaudeAgent({ verbose: options.verbose });
468→      newParsers.set(file.label, parserAgent.parser);
469→    }
470→    parsers = newParsers;
471→
472→    // 重新建立 multiWatcher（先建立，但還不啟動）
473→    const newMultiWatcher = new MultiFileWatcher();
474→
475→    // 重新建立 detector（捕獲新的 multiWatcher，沿用 pane 回呼）
476→    const newDetector = new SubagentDetector(newExistingAgentIds, {
477→      subagentsDir: newSubagentsDir,
478→      output: new ConsoleOutputHandler(),
479→      watcher: { addFile: (f) => newMultiWatcher.addFile(f) },
480→      session: new NoOpSessionHandler(),
481→      enabled: options.follow && options.withSubagents,
482→      onNewSubagent: openPaneForSubagent,
483→      onSubagentEnter: openPaneForSubagent,
484→      onSubagentDone,
485→      hasPane: hasPaneCallback,
486→    });
487→    newDetector.startDirectoryWatch();
488→
489→    // 更新外層變數
490→    subagentsDir = newSubagentsDir;
491→    multiWatcher = newMultiWatcher;
492→    detector = newDetector;
493→
494→    // 重新啟動監控
495→    await multiWatcher.start(newFiles, {
496→      follow: options.follow,
497→      pollInterval: options.sleepInterval,
498→      initialLines: options.lines,
499→      onLine: createOnLineHandler({
500→        parsers,
501→        formatter,
502→        detector,
503→        onOutput: (formatted) => console.log(formatted),
504→        verbose: options.verbose,
505→        shouldOutput,
506→      }),
507→      onError: (error) => {
508→        console.error(chalk.red(`Error: ${error.message}`));
509→      },
510→    });
511→  };
512→
513→  const superFollow = createSuperFollowController({
514→    projectDir,
515→    getCurrentPath: () => currentSessionPath,
516→    onSwitch: switchToSession,
517→    autoSwitch: options.autoSwitch,
518→    findLatestInProject: findLatestMainSessionInProject,
519→  });
520→
521→  // 處理中斷信號
522→  process.on('SIGINT', () => {
523→    superFollow.stop();
524→    console.log(chalk.gray('\nStopping...'));
525→    detector?.stop();
526→    multiWatcher.stop();
527→    // best-effort 清理所有 pane（async 但不等待，因為即將 exit）
528→    paneManager?.closeAll();
529→    process.exit(0);
530→  });
531→
532→  await multiWatcher.start(files, {
533→    follow: options.follow,
534→    pollInterval: options.sleepInterval,
535→    initialLines: options.lines,
536→    onLine: createOnLineHandler({
537→      parsers,
538→      formatter,
539→      detector,
540→      onOutput: (formatted) => console.log(formatted),
541→      verbose: options.verbose,
542→      shouldOutput,
543→    }),
544→    onError: (error) => {
545→      console.error(chalk.red(`Error: ${error.message}`));
546→    },
547→  });
548→
549→  // 如果不是 follow 模式，結束程式
550→  if (!options.follow) {
551→    process.exit(0);
552→  }
553→
554→  // 啟動 super-follow
555→  superFollow.start();
