561→/**
562→ * 時間排序輸出（用於 --no-follow --with-subagents 模式）
563→ * 收集所有檔案的行，按時間戳排序後輸出
564→ */
565→async function outputTimeSorted(
566→  files: WatchedFile[],
567→  parsers: Map<string, LineParser>,
568→  formatter: Formatter,
569→  _options: CliOptions
570→): Promise<void> {
571→  // 收集所有已解析的行
572→  const allParsedLines: Array<{
573→    parsed: import('./core/types.ts').ParsedLine;
574→    timestamp: Date;
575→  }> = [];
576→
577→  for (const file of files) {
578→    const parser = parsers.get(file.label);
579→    if (!parser) continue;
580→
581→    // 讀取檔案內容
582→    const bunFile = Bun.file(file.path);
583→    if (!(await bunFile.exists())) continue;
584→
585→    const content = await bunFile.text();
586→    const lines = content.split('\n').filter((line) => line.trim());
587→
588→    for (const line of lines) {
589→      let parsed = parser.parse(line);
590→      while (parsed) {
591→        parsed.sourceLabel = file.label;
592→        allParsedLines.push({
593→          parsed,
594→          timestamp: new Date(parsed.timestamp),
595→        });
596→        parsed = parser.parse(line);
597→      }
598→    }
599→  }

 600→
 601→  // 按時間戳排序（舊到新）
 602→  allParsedLines.sort((a, b) => a.timestamp.getTime() - b.timestamp.getTime());
 603→
 604→  // 依序輸出
 605→  for (const { parsed } of allParsedLines) {
 606→    console.log(formatter.format(parsed));
 607→  }
 608→}
