 610→/**
 611→ * Interactive 模式共用：建立 SessionManager（Claude/Codex 兩種 interactive 模式都相同）
 612→ */
 613→function createInteractiveSessionManager(
 614→  displayController: DisplayController
 615→): SessionManager {
 616→  const manager = new SessionManager({
 617→    bufferSize: 1000,
 618→    onOutput: (content: string, _session: WatcherSession) => {
 619→      displayController.write(content);
 620→    },
 621→    onSessionAdded: (session: WatcherSession) => {
 622→      displayController.write(
 623→        chalk.yellow(`New session added: ${session.label}`)
 624→      );
 625→      displayController.updateStatusLine(
 626→        manager.getAllSessions(),
 627→        manager.getActiveIndex()
 628→      );
 629→    },
 630→    onSessionSwitched: (
 631→      session: WatcherSession,
 632→      allSessions: WatcherSession[]
 633→    ) => {
 634→      const historyContent = session.buffer.slice();
 635→      displayController.updateStatusLine(allSessions, manager.getActiveIndex());
 636→      displayController.showSwitchMessage(session, historyContent);
 637→    },
 638→  });
 639→  return manager;
 640→}
