 642→/**
 643→ * Claude Interactive 模式（使用 SessionManager 和 DisplayController 管理輸出切換）
 644→ */
 645→async function startClaudeInteractiveWatch(
 646→  sessionFile: SessionFile,
 647→  formatter: Formatter,
 648→  options: CliOptions,
 649→  initialSubagent: SessionFile | null = null
 650→): Promise<void> {
 651→  // TTY 檢查：非 TTY 環境自動降級到普通多檔案監控模式
 652→  if (!process.stdin.isTTY) {
 653→    console.warn(
 654→      chalk.yellow(
 655→        'Warning: Interactive mode not available in non-TTY environment.\n' +
 656→          'Switching to standard multi-watch mode.\n' +
 657→          'Keyboard controls (Tab to switch) will not be available.'
 658→      )
 659→    );
 660→    await startClaudeMultiWatch(
 661→      sessionFile,
 662→      formatter,
 663→      options,
 664→      initialSubagent
 665→    );
 666→    return;
 667→  }
 668→
 669→  const lockedProjectDir = dirname(sessionFile.path);
 670→
 671→  // 建立 DisplayController
 672→  const displayController = new DisplayController({
 673→    persistentStatusLine: true,
 674→    historyLines: 50,
 675→  });
 676→
 677→  let sessionManager!: SessionManager;
 678→  let parsers = new Map<string, LineParser>();
 679→  let multiWatcher: MultiFileWatcher | null = null;
 680→  let detector: SubagentDetector | null = null;
 681→  let currentSessionFile = sessionFile;
 682→
 683→  const buildInteractiveState = async (
 684→    targetSessionFile: SessionFile,
 685→    initialSubagentFile: SessionFile | null,
 686→    showIntro: boolean
 687→  ): Promise<void> => {
 688→    const subagentsDir = getSubagentsDir(targetSessionFile.path);
 689→
 690→    sessionManager = createInteractiveSessionManager(displayController);
 691→    sessionManager.addSession('main', MAIN_LABEL, targetSessionFile.path);
 692→
 693→    // 掃描現有的 subagent（優先使用目錄掃描，確保找到所有檔案）
 694→    const dirAgentIds = await scanForNewSubagents(subagentsDir, new Set());
 695→    const existingAgentIds = new Set(dirAgentIds);
 696→
 697→    // 如果有從 sessionId 指定的 subagent，確保它被加入
 698→    if (initialSubagentFile) {
 699→      const initialAgentId = basename(
 700→        initialSubagentFile.path,
 701→        '.jsonl'
 702→      ).replace(/^agent-/, '');
 703→      existingAgentIds.add(initialAgentId);
 704→    }
 705→
 706→    const existingSubagentFiles = await buildSubagentFiles(
 707→      subagentsDir,
 708→      existingAgentIds
 709→    );
 710→    for (const { agentId, path } of existingSubagentFiles) {
 711→      sessionManager.addSession(agentId, makeAgentLabel(agentId), path);
 712→    }
 713→
 714→    if (showIntro) {
 715→      if (existingAgentIds.size > 0) {
 716→        log(
 717→          options.quiet,
 718→          chalk.gray(`Found ${existingAgentIds.size} subagent(s)`)
 719→        );
 720→      }
 721→      log(
 722→        options.quiet,
 723→        chalk.gray('Interactive mode: Press Tab to switch, q to quit')
 724→      );
 725→      log(options.quiet, chalk.gray('---'));
 726→    }
 727→
 728→    // 為每個來源建立獨立的 parser
 729→    parsers = new Map<string, LineParser>();
 730→    for (const session of sessionManager.getAllSessions()) {
 731→      const parserAgent = new ClaudeAgent({ verbose: options.verbose });
 732→      parsers.set(session.label, parserAgent.parser);
 733→    }
 734→
 735→    const watcher = new MultiFileWatcher();
 736→    multiWatcher = watcher;
 737→
 738→    detector = new SubagentDetector(existingAgentIds, {
 739→      subagentsDir,
 740→      output: new DisplayControllerOutputHandler(displayController),
 741→      watcher: { addFile: (f) => watcher.addFile(f) },
 742→      session: new InteractiveSessionHandler(sessionManager, displayController),
 743→      enabled: true, // Interactive 模式一定是 follow
 744→    });
 745→    detector.startDirectoryWatch();
 746→  };
 747→
 748→  const startWatcher = async (): Promise<void> => {
 749→    if (!multiWatcher || !detector) return;
 750→    const activeDetector = detector;
 751→
 752→    const files = sessionManager.getWatchedFiles();
 753→
 754→    await multiWatcher.start(files, {
 755→      follow: options.follow,
 756→      pollInterval: options.sleepInterval,
 757→      initialLines: options.lines,
 758→      onLine: createOnLineHandler({
 759→        parsers,
 760→        formatter,
 761→        detector: activeDetector,
 762→        onOutput: (formatted, label) =>
 763→          sessionManager.handleOutput(label, formatted),
 764→        verbose: options.verbose,
 765→      }),
 766→      onError: (error) => {
 767→        displayController.write(chalk.red(`Error: ${error.message}`));
 768→      },
 769→    });
 770→  };
 771→
 772→  // 設定鍵盤監聽
 773→  if (process.stdin.isTTY) {
 774→    process.stdin.setRawMode(true);
 775→    process.stdin.resume();
 776→    process.stdin.setEncoding('utf8');
 777→
 778→    process.stdin.on('data', (key: string) => {
 779→      // Ctrl+C
 780→      if (key === '\u0003') {
 781→        cleanup();
 782→        process.exit(0);
 783→      }
 784→      // q - quit
 785→      if (key === 'q' || key === 'Q') {
 786→        cleanup();
 787→        process.exit(0);
 788→      }
 789→      // Tab - switch next
 790→      if (key === '\t') {
 791→        sessionManager.switchNext();
 792→      }
 793→      // Shift+Tab (varies by terminal, common: \u001b[Z)
 794→      if (key === '\u001b[Z') {
 795→        sessionManager.switchPrev();
 796→      }
 797→      // n - switch next (alternative)
 798→      if (key === 'n' || key === 'N') {
 799→        sessionManager.switchNext();
 800→      }
 801→      // p - switch prev (alternative)
 802→      if (key === 'p' || key === 'P') {
 803→        sessionManager.switchPrev();
 804→      }
 805→    });
 806→  }
 807→
 808→  // 初始化狀態並啟動監控
 809→  await buildInteractiveState(currentSessionFile, initialSubagent, true);
 810→
 811→  // 初始化 DisplayController
 812→  displayController.init();
 813→
 814→  // 顯示初始狀態列
 815→  displayController.updateStatusLine(
 816→    sessionManager.getAllSessions(),
 817→    sessionManager.getActiveIndex()
 818→  );
 819→
 820→  await startWatcher();
 821→
 822→  const switchToSession = async (
 823→    nextSessionFile: SessionFile
 824→  ): Promise<void> => {
 825→    detector?.stop();
 826→    if (multiWatcher) {
 827→      multiWatcher.stop();
 828→    }
 829→
 830→    currentSessionFile = nextSessionFile;
 831→    await buildInteractiveState(nextSessionFile, null, false);
 832→
 833→    displayController.updateStatusLine(
 834→      sessionManager.getAllSessions(),
 835→      sessionManager.getActiveIndex()
 836→    );
 837→
 838→    await startWatcher();
 839→
 840→    const nextSessionId = basename(nextSessionFile.path, '.jsonl');
 841→    displayController.write(
 842→      chalk.gray(`Switched to latest session: ${nextSessionId}`)
 843→    );
 844→  };
 845→
 846→  const superFollow = createSuperFollowController({
 847→    projectDir: lockedProjectDir,
 848→    getCurrentPath: () => currentSessionFile.path,
 849→    onSwitch: switchToSession,
 850→    autoSwitch: options.autoSwitch,
 851→    findLatestInProject: findLatestMainSessionInProject,
 852→  });
 853→
 854→  superFollow.start();
 855→
 856→  // 清理函式
 857→  const cleanup = (): void => {
 858→    superFollow.stop();
 859→    // 先清理 DisplayController（恢復終端設定）
 860→    displayController.destroy();
 861→    detector?.stop();
 862→    log(options.quiet, chalk.gray('\nStopping...'));
 863→    if (process.stdin.isTTY) {
 864→      process.stdin.setRawMode(false);
 865→    }
 866→    if (multiWatcher) {
 867→      multiWatcher.stop();
 868→    }
 869→  };
 870→
 871→  // 處理中斷信號
 872→  process.on('SIGINT', () => {
 873→    cleanup();
 874→    process.exit(0);
 875→  });
 876→
 877→  // 保持程式運行（interactive 模式必須是 follow）
 878→  displayController.write(
 879→    chalk.gray('Watching for changes... (Tab to switch, q to quit)')
 880→  );
 881→}
