 999→
1000→  const startWatcher = async (): Promise<void> => {
1001→    if (!multiWatcher) return;
1002→
1003→    const files = sessionManager.getWatchedFiles();
1004→
1005→    await multiWatcher.start(files, {
1006→      follow: true, // Interactive 一定是 follow
